func channelIcon(channel string) templ.Component {
	switch channel {
	case "email":
		return icons.Mail(icons.WithSize(20))
	case "sms":
		return icons.MessageSquare(icons.WithSize(20))
	case "inapp":
		return icons.Bell(icons.WithSize(20))
	case "push":
		return icons.Smartphone(icons.WithSize(20))
	default:
		return icons.Layers(icons.WithSize(20))
	}
}

